using System;
using System.Collections.Generic;
using System.IO;
using System.Text.Json;
using System.Threading;
using System.Threading.Tasks;
using LauncherV2.Core;

namespace LauncherV2.Plugins.Emulated.Games;

// ═══════════════════════════════════════════════════════════════════════════════
// AdventurePlugin — Archipelago integration for Adventure (Atari 2600), on the
// proven BizHawk Lua-pipe bridge.
//
// STATUS: goal + the three dragon-slay checks are REAL and SOURCE-DERIVED. The
// detectable location id list and the dragon-slay mapping in adventure.lua were
// GENERATED by parsing worlds/adventure/Locations.py (ap_id = short_location_id +
// 118000000, verified for all 24 entries); the RAM addresses and the
// dead-dragon transition / victory logic are replicated EXACTLY from the official
// data/lua/connector_adventure.lua, and mock-verified through MoonSharp against
// synthetic Atari 2600 RAM. items_handling = 0b111.
//
// PARTIAL-BUT-CORRECT COVERAGE — IMPORTANT: Adventure's 24 detectable locations
// split into two kinds. The 3 dragon-slay checks (Rhindle/Yorgle/Grundle) and the
// victory goal are computable from the 2600's tiny RAM alone and ARE reported. The
// other 21 (the Blue Labyrinth / Catacombs / castle-vault / credits-room pickups)
// are detected by the official connector ONLY with per-seed PATCH DATA — foreign-
// item room placements + local-item→location maps — that Adventure's dedicated
// AdventureClient pushes to connector_adventure.lua over its own TCP socket. The
// launcher's generic CHECK/GOAL/SYNC bridge does not carry that mapping, so those
// pickups cannot be attributed to a location id from RAM alone; reporting them
// would be guesswork, so they are GATED (documented in adventure.lua) rather than
// shipped wrong. ChecksImplemented is therefore true (goal + dragon slays are
// genuine, source-exact checks), with the room/item pickups the documented
// deferred piece. Full multiworld coverage is the dedicated AdventureClient's job.
//
// HOW ADVENTURE IS RANDOMIZED — IMPORTANT: like Final Fantasy 1, Adventure is NOT
// patched by the launcher. Its AP output is a custom AdventureDeltaPatch container
// (.apadvn — a zip of rom_deltas + a bsdiff4 basepatch, NOT an APProcedurePatch),
// and it is applied by Adventure's OWN dedicated client (AdventureClient.py), which
// rebuilds the ROM and writes a *.a26 next to the patch. The player loads that
// already-built .a26 (or, equivalently, points at their licensed vanilla
// ADVNTURE.BIN that the dedicated client patches). The launcher applies no patch of
// its own; PrepareSessionRomAsync returns null and the base class launches the ROM
// directly (§11: the library copy, original untouched). Base ROM: the standard NTSC
// Adventure cartridge dump — 4096 bytes, MD5 157bddb7192754a45372be196797f284 —
// identified by CONTENT, never by filename (§11). The dedicated client's per-seed
// .a26 is also 4096 bytes (a 4 KB cartridge stays 4 KB) but has a seed-specific MD5,
// so any 4 KB file is accepted at import and the vanilla MD5 is the known dump.
// ═══════════════════════════════════════════════════════════════════════════════

public sealed class AdventurePlugin : EmulatorPlugin
{
    public AdventurePlugin() => LoadSettings();

    // ── Identity ──────────────────────────────────────────────────────────────

    public override string GameId      => "adventure";
    public override string DisplayName => "Adventure";
    public override string Subtitle    => "Atari 2600 · Emulated";
    public override string ApWorldName => "Adventure";

    public override string Description =>
        "Adventure, the 1980 Atari 2600 original that defined the action-adventure " +
        "genre. In the Archipelago randomizer, the keys, sword, bridge, magnet and " +
        "chalice are shuffled into the multiworld, the three dragons can roam new " +
        "lairs, and slaying each one is a check. Find the enchanted chalice and " +
        "return it to the yellow castle to complete your goal — and beware the bat.";

    public override string ThemeAccentColor => "#C8761A";   // Atari 2600 amber

    // ── Emulator specifics ────────────────────────────────────────────────────

    protected override string RomSystem     => "A26";

    // §14: the Atari 2600 runs on BizHawk only (its Atari2600Hawk core is what the
    // apworld + connector_adventure.lua target). No snes9x / mGBA / Mesen — none
    // host the 2600.
    protected override IReadOnlyList<string> SupportedEmulatorIds =>
        new[] { "bizhawk" };
    protected override string LuaScriptName => "bizhawk_ap_connector.lua";
    protected override string LuaModuleName => "adventure";

    /// adventure.lua reports the goal + the three dragon-slay checks (generated
    /// from the apworld; transition/victory logic from connector_adventure.lua;
    /// mock-verified). The 21 room/item pickups need the dedicated client's
    /// per-seed patch-data socket feed and are the documented gated piece.
    public override bool ChecksImplemented => true;

    /// The ROM the player loads is the standard NTSC Adventure cartridge — the
    /// dedicated AdventureClient patches it (or loads its already-built .a26) — so
    /// it is identified by CONTENT, never by filename (§11). Adventure is a 4 KB
    /// cartridge: 4096 bytes, MD5 157bddb7192754a45372be196797f284 for the vanilla
    /// dump. The dedicated client's per-seed .a26 is also 4096 bytes but has a
    /// seed-specific MD5, so a 4 KB file is accepted at import (size is the stable
    /// detector) and the vanilla MD5 is recorded as the known good dump.
    protected override IReadOnlyList<RomIdentity> AcceptableBaseRoms => new[]
    {
        new RomIdentity(4096, "157bddb7192754a45372be196797f284",
                        "Adventure (NTSC) — standard cartridge dump"),
        new RomIdentity(4096, null,
                        "Adventure (NTSC) — Archipelago-built .a26 from the Adventure Client"),
    };

    // ── AP patch ────────────────────────────────────────────────────────────────
    //
    // Adventure has no APProcedurePatch the launcher can apply (its .apadvn is a
    // custom AdventureDeltaPatch applied by the dedicated AdventureClient — see the
    // header). We keep the standard hook shape for consistency with the other
    // emulated games, but the resolver is only an optional override: a player who
    // ever drops an explicit container in Settings would have it honored; otherwise
    // the already-built .a26 (or vanilla .bin) is loaded directly with no patch step.

    private const string PatchExt = ".apadvn";

    /// Explicit patch override chosen by the user (Settings / drag-drop). Null =
    /// none — the normal Adventure path, the ROM is loaded as-is.
    public string? ApPatchPath { get; private set; }

    protected override void OnSavingSettings(IDictionary<string, object?> bag)
        => bag["ap_patch_path"] = ApPatchPath;

    protected override void OnLoadingSettings(JsonElement root)
    {
        if (root.TryGetProperty("ap_patch_path", out var el)) ApPatchPath = el.GetString();
    }

    /// Set an explicit patch override (rare for Adventure) and persist it.
    public void SetExplicitPatch(string path) { ApPatchPath = path; SaveSettings(); }

    /// ROM safety net. Adventure has no launcher-applied patch carrying an expected
    /// MD5, so the only requirement we can surface is "an Adventure ROM is present"
    /// — the player supplies the .a26 the dedicated client built (or the vanilla
    /// cartridge dump). A future explicit .apadvn override (which the launcher does
    /// not apply itself) would still demand its base MD5 if one were set.
    public override RomRequirement? GetUnmetRomRequirement()
    {
        var patch = SnesApPatchHelper.ResolvePatch(
            PatchExt, ApPatchPath, GetSeedName?.Invoke(), CurrentSlotName, out _);
        string? wantMd5 = patch != null
            ? SnesApPatchHelper.ReadManifestField(patch, "base_checksum") : null;
        bool haveRom = RomPath != null && File.Exists(RomPath);

        if (wantMd5 == null)
            return haveRom ? null
                 : new RomRequirement("Adventure", "A26",
                       "your Adventure (NTSC) ROM — the .a26 built by the Adventure " +
                       "Client, or your licensed cartridge dump",
                       RequiredMd5: null, WrongVersionPresent: false, BuildRomFilter());

        if (haveRom && ComputeMd5(RomPath!).Equals(wantMd5, StringComparison.OrdinalIgnoreCase))
            return null;

        return new RomRequirement("Adventure", "A26",
            "Adventure (NTSC) — the exact ROM this patch was generated against",
            wantMd5, WrongVersionPresent: haveRom, BuildRomFilter());
    }

    // ── Session ROM ───────────────────────────────────────────────────────────
    //
    // The normal Adventure path applies NO patch — the player's library ROM IS the
    // .a26 the dedicated AdventureClient built (or a vanilla dump it patches), so we
    // return null and the base class launches it directly. Only an explicit .apadvn
    // override (which the launcher does not apply itself) would trigger the shared
    // helper; that branch is kept for parity but is inert for standard Adventure
    // seeds.

    protected override async Task<string?> PrepareSessionRomAsync(
        ApSession session, CancellationToken ct)
    {
        string? patch = SnesApPatchHelper.ResolvePatch(
            PatchExt, ApPatchPath, GetSeedName?.Invoke(), CurrentSlotName, out string how);
        if (patch == null)
        {
            // Standard Adventure: the launcher applies no patch. The library ROM is
            // the .a26 the Adventure Client built from the .apadvn (or the vanilla
            // cartridge the dedicated client patches).
            SessionRomNote =
                "[Adventure] Adventure's ROM is built by the Archipelago Adventure " +
                "Client from its .apadvn patch (not by the launcher) — launching your " +
                "ROM directly. Load the .a26 the Adventure Client produced (or your " +
                "licensed Adventure cartridge dump).";
            return null;
        }

        // Optional explicit-override path (kept for parity; the launcher does not
        // apply .apadvn itself for standard seeds).
        var res = await SnesApPatchHelper.ApplyAsync(
            "Adventure", patch, how, RomPath!,
            RomLibraryDirectory, ".a26", ct);
        SessionRomNote = res.Note;
        if (res.OutRom != null) RegisterSeed(res.OutRom, patch);
        return res.OutRom;
    }

    /// Record a produced/reused patched ROM in the seed library. Never throws.
    /// (Only reached on the optional explicit-override path — standard Adventure
    /// seeds launch the dedicated client's .a26 directly and never get here.)
    private void RegisterSeed(string outRom, string patch)
    {
        try
        {
            SeedLibraryStore.Instance.Register(new SeedEntry
            {
                GameId         = GameId,
                PatchedRomPath = outRom,
                PatchPath      = patch,
                SeedName       = SnesApPatchHelper.ParseSeedFromPatch(patch),
                SlotName       = CurrentSlotName ?? "",
                CreatedUtc     = DateTimeOffset.UtcNow,
            });
        }
        catch { /* registry is non-essential to launching */ }
    }
}
